(function(){
/* Etiquetas personalizadas para las opciones del select de orden.
   Los valores coinciden con los que envía el plugin (name="sp_filter_order").
   Los valores custom (featured, instock) los procesa el tema vía pre_get_posts. */
var ORDER_LABELS={
  relevance:"Relevancia",
  price_asc:"Precio ascendente",
  price_desc:"Precio descendente",
  popularity:"Más vendidos",
  date_newest:"Novedades"
};

var patchOrderSelect=function(select){
  if(!select||select.getAttribute("data-fq-patched")==="true"){return}
  Array.prototype.forEach.call(select.options,function(opt){
    if(ORDER_LABELS[opt.value]){opt.textContent=ORDER_LABELS[opt.value]}
  });
  select.setAttribute("data-fq-patched","true")
};

var findOrderItem=function(sidebar){var items=sidebar.querySelectorAll(".sp-filter-item");for(var i=0;i<items.length;i+=1){if(items[i].querySelector("#sp-filter-order")){return items[i]}}return null};
var syncResetVisibility=function(sidebar){var resetButton=sidebar.querySelector("#sp-filter-reset");if(!resetButton){return}var checkboxes=sidebar.querySelectorAll('input[type="checkbox"]:checked');var hasChecked=false;checkboxes.forEach(function(input){if(!input.id||!/archive$/.test(input.id)){hasChecked=true}});var minInput=sidebar.querySelector("#sp-filter-min-price");var maxInput=sidebar.querySelector("#sp-filter-max-price");var minChanged=false;var maxChanged=false;if(minInput&&typeof window.min_price_filter!=="undefined"){minChanged=Number(minInput.value||window.min_price_filter)!==Number(window.min_price_filter)}if(maxInput&&typeof window.max_price_filter!=="undefined"){maxChanged=Number(maxInput.value||window.max_price_filter)!==Number(window.max_price_filter)}resetButton.style.display=hasChecked||minChanged||maxChanged?"inline-flex":"none"};
var createCard=function(title,icon,modifier){var card=document.createElement("section");card.className="fq-filter-card fq-filter-card--"+modifier;var head=document.createElement("div");head.className="fq-filter-card__head";var heading=document.createElement("h3");heading.className="fq-filter-card__title";heading.textContent=title;var actions=document.createElement("div");actions.className="fq-filter-card__actions";var iconWrap=document.createElement("span");iconWrap.className="fq-filter-card__icon";iconWrap.setAttribute("aria-hidden","true");iconWrap.innerHTML='<span class="material-symbols-outlined">'+icon+"</span>";actions.appendChild(iconWrap);head.appendChild(heading);head.appendChild(actions);var body=document.createElement("div");body.className="fq-filter-card__body";card.appendChild(head);card.appendChild(body);return card};
var moveItemToCard=function(card,item){if(!card||!item){return}var body=card.querySelector(".fq-filter-card__body");if(body&&item.parentNode!==body){body.appendChild(item)}};
var ensureResetButton=function(sidebar){var resetButton=sidebar.querySelector("#sp-filter-reset");if(resetButton){return resetButton}resetButton=document.createElement("button");resetButton.type="button";resetButton.id="sp-filter-reset";resetButton.textContent="Limpiar";resetButton.style.display="none";return resetButton};
var injectPromoBanner=function(){var source=document.querySelector("[data-fq-product-cat-promo]");if(!source){return}var promoMarkup=source.firstElementChild;if(!promoMarkup){return}document.querySelectorAll(".sp-filter-products-container").forEach(function(container){if(container.querySelector(".fq-product-cat-promo")){return}var productsList=container.querySelector("#sp-filter-products-list");var promoClone=promoMarkup.cloneNode(true);if(productsList){container.insertBefore(promoClone,productsList)}else{container.insertBefore(promoClone,container.firstChild)}})};

var enhanceSidebar=function(sidebar){
  if(!sidebar){return}
  if(sidebar.getAttribute("data-fq-filter-enhanced")==="true"){syncResetVisibility(sidebar);return}
  var orderItem=findOrderItem(sidebar);
  var categoryItem=sidebar.querySelector(".sp-filter-categories");
  var priceItem=sidebar.querySelector(".sp-filter-price-range");
  var tagItem=sidebar.querySelector(".sp-filter-etiquetas");
  var attributesItem=sidebar.querySelector(".sp-filter-attributes");
  var brandItem=sidebar.querySelector(".sp-filter-marcas");
  var applyWrap=sidebar.querySelector(".sp-filter-apply-wrapper");
  var orderCard=orderItem?createCard("Ordenar por","sort","order"):null;
  var categoryCard=categoryItem?createCard("Subcategorías","category","categories"):null;
  var filterItems=[priceItem,tagItem,attributesItem,brandItem,applyWrap].filter(function(item){return!!item});
  var filtersCard=filterItems.length?createCard("Filtros","tune","filters"):null;
  if(orderCard){sidebar.insertBefore(orderCard,sidebar.firstChild);moveItemToCard(orderCard,orderItem)}
  if(categoryCard){sidebar.appendChild(categoryCard);moveItemToCard(categoryCard,categoryItem)}
  if(filtersCard){
    sidebar.appendChild(filtersCard);
    filterItems.forEach(function(item){moveItemToCard(filtersCard,item)});
    var resetButton=ensureResetButton(sidebar);
    var actions=filtersCard.querySelector(".fq-filter-card__actions");
    if(actions&&!actions.querySelector("#sp-filter-reset")){actions.insertBefore(resetButton,actions.firstChild)}
  }
  // Parchear el select de orden
  var orderSelect=sidebar.querySelector("#sp-filter-order");
  if(orderSelect){patchOrderSelect(orderSelect)}
  sidebar.setAttribute("data-fq-filter-enhanced","true");
  syncResetVisibility(sidebar)
};

var enhanceAll=function(){
  document.querySelectorAll(".sp-filter-sidebar").forEach(function(sidebar){enhanceSidebar(sidebar)});
  injectPromoBanner();
  // Parchear selects que aparezcan fuera del sidebar (mobile overlay, etc.)
  document.querySelectorAll("#sp-filter-order").forEach(function(sel){patchOrderSelect(sel)})
};

if(document.readyState==="loading"){document.addEventListener("DOMContentLoaded",enhanceAll)}else{enhanceAll()}
window.addEventListener("load",enhanceAll);
window.setTimeout(enhanceAll,350);
window.setTimeout(enhanceAll,900);

document.addEventListener("change",function(event){var target=event.target;if(!(target instanceof HTMLElement)){return}var sidebar=target.closest(".sp-filter-sidebar");if(sidebar){window.setTimeout(function(){syncResetVisibility(sidebar);injectPromoBanner()},10)}});
document.addEventListener("click",function(event){var target=event.target;if(!(target instanceof HTMLElement)){return}var sidebar=target.closest(".sp-filter-sidebar");if(sidebar&&(target.id==="sp-filter-reset"||target.id==="sp-filter-apply"||target.closest(".ui-slider-handle"))){window.setTimeout(function(){syncResetVisibility(sidebar);injectPromoBanner()},60)}});

/* Reemplaza las flechas de texto de la paginación por iconos Material Symbols */
var patchPagination=function(){var pagination=document.getElementById("sp-filter-pagination");if(!pagination||pagination.getAttribute("data-fq-pages-patched")==="true"){return}var prev=pagination.querySelector(".page-numbers.prev");var next=pagination.querySelector(".page-numbers.next");if(prev){prev.innerHTML='<span class="material-symbols-outlined" style="font-size:18px;line-height:1">chevron_left</span>'}if(next){next.innerHTML='<span class="material-symbols-outlined" style="font-size:18px;line-height:1">chevron_right</span>'}pagination.setAttribute("data-fq-pages-patched","true")};
var enhanceAllFull=function(){document.querySelectorAll(".sp-filter-sidebar").forEach(function(sidebar){enhanceSidebar(sidebar)});injectPromoBanner();document.querySelectorAll("#sp-filter-order").forEach(function(sel){patchOrderSelect(sel)});patchPagination()};
window.addEventListener("load",enhanceAllFull);
window.setTimeout(enhanceAllFull,900);
document.addEventListener("sp_filter_loaded",function(){window.setTimeout(patchPagination,60)})
})();
